Here are the public test cases for feature1_decode:
{
  "description": "Decode a Bech32-encoded value into its raw data payload, the embedded witness/header version byte, and the human-readable prefix, and report whether the input is well formed. The implementation follows the Bech32 specification used for blockchain address encoding.",
  "cases": [
    {
      "input": {
        "op": "bech32_decode",
        "address": "stake1uyehkck0lajq8gr28t9uxnuvgcqrc6070x3k9r8048z8y5gh6ffgw"
      },
      "expected_output": "data_hex=e1337b62cfff6403a06a3acbc34f8c46003c69fe79a3628cefa9c47251\nversion=28\nhrp=stake\nvalid=true"
    }
  ]
}

Here are the public test cases for feature1_is_valid_false:
{
  "description": "A validity predicate reports false for inputs that are not well-formed Bech32 strings, including a null reference, empty or whitespace-only text, strings with no separator or an out-of-range character, and strings carrying a corrupted checksum.",
  "cases": [
    {
      "input": {
        "op": "bech32_is_valid",
        "value": null
      },
      "expected_output": "valid=false"
    },
    {
      "input": {
        "op": "bech32_is_valid",
        "value": "1nwldj5"
      },
      "expected_output": "valid=false"
    }
  ]
}

Here are the public test cases for feature2_parse:
{
  "description": "Parse a Bech32 address string into a structured address, exposing its raw byte payload as hex, its human-readable prefix, the network it belongs to, and the address type (payment-with-stake base addresses here).",
  "cases": [
    {
      "input": {
        "op": "address_parse",
        "address": "addr1q8d9pcrn38veygv638ftw0f82gm4h6rmrs599pkr3qfxx073eyjrmj0hnx6xz8emx03l6hszjclm8fmnlaewe4adp7dqsd8pa6"
      },
      "expected_output": "data_hex=01da50e07389d992219a89d2b73d2752375be87b1c285286c38812633fd1c9243dc9f799b4611f3b33e3fd5e02963fb3a773ff72ecd7ad0f9a\nprefix=addr\nnetwork=Mainnet\naddress_type=Base"
    }
  ]
}

Here are the public test cases for feature3_entropy:
{
  "description": "Restore a mnemonic phrase back to the raw entropy it encodes, returned as a hex string. This is the inverse of generating a phrase from entropy under the BIP39 scheme.",
  "cases": [
    {
      "input": {
        "op": "mnemonic_to_entropy",
        "mnemonic": "elder lottery unlock common assume beauty grant curtain various horn spot youth exclude rude boost fence used two spawn toddler soup awake across use"
      },
      "expected_output": "entropy_hex=475083b81730de275969b1f18db34b7fb4ef79c66aa8efdd7742f1bcfe204097"
    }
  ]
}

Here are the public test cases for feature3_wordlist_membership:
{
  "description": "For each supported language, the corresponding BIP39 wordlist contains a set of known sample words drawn from that language. Membership is checked word by word.",
  "cases": [
    {
      "input": {
        "op": "wordlist_contains",
        "language": "English",
        "words": [
          "abandon",
          "lend",
          "zoo"
        ]
      },
      "expected_output": "abandon=true\nlend=true\nzoo=true"
    }
  ]
}

Here are the public test cases for feature4_root_key:
{
  "description": "Derive the root (master) extended private key from a restored mnemonic, returning the 64-byte key half and the 32-byte chain code as hex.",
  "cases": [
    {
      "input": {
        "op": "mnemonic_root_key",
        "mnemonic": "art forum devote street sure rather head chuckle guard poverty release quote oak craft enemy"
      },
      "expected_output": "key_hex=b8f2bece9bdfe2b0282f5bad705562ac996efb6af96b648f4445ec44f47ad95c10e3d72f26ed075422a36ed8585c745a0e1150bcceba2357d058636991f38a37\nchaincode_hex=91e248de509c070d812ab2fda57860ac876bc489192c1ef4ce253c197ee219a4"
    }
  ]
}

Here are the public test cases for feature5_invalid:
{
  "description": "Strings that are neither a complete hardened path nor a valid soft tail are rejected when constructing a path. Each such input surfaces as a normalized invalid-path error.",
  "cases": [
    {
      "input": {
        "op": "path_invalid",
        "path": "m/1852'/1815'"
      },
      "expected_output": "error=invalid_path"
    }
  ]
}

Here are the public test cases for feature5_parse:
{
  "description": "Parse a full derivation path string into its components: purpose, coin type, account index, role, and index. Re-rendering the parsed path reproduces the original string.",
  "cases": [
    {
      "input": {
        "op": "path_parse",
        "path": "m/44'/1815'/0'/0/0"
      },
      "expected_output": "path=m/44'/1815'/0'/0/0\npurpose=Byron\ncoin=Ada\naccount_index=0\nrole=ExternalChain\nindex=0"
    }
  ]
}

Here are the public test cases for feature6_blake2b224:
{
  "description": "Compute the 28-byte Blake2b-224 hash of a byte input, returned as hex. This is the key-hash function used to derive credential and key hashes.",
  "cases": [
    {
      "input": {
        "op": "blake2b224",
        "data_hex": "848AC717B552FCD1F2DCB4933E4A8198187E7E424693B51E1B8B16250F3CADFE"
      },
      "expected_output": "hash_hex=5cd719e99fdd80fd889e82cf012e64d5da7ab35364bb02163bc93974"
    }
  ]
}

Here are the public test cases for feature7_last_bits:
{
  "description": "Extract the least-significant N bits of a single byte, returning the resulting integer value.",
  "cases": [
    {
      "input": {
        "op": "last_bits",
